"""UxComponentResult — immutable domain model for generated UX components."""

from __future__ import annotations

from pydantic import BaseModel, Field


class GeneratedUxComponent(BaseModel, frozen=True):
    """A single React component generated by SKILL-UX-02."""

    name: str = Field(description="Component name in PascalCase (e.g. 'ConfirmationDialog').")
    file_path: str = Field(
        description="Relative path within the frontend project (e.g. 'presentation/components/ConfirmationDialog.tsx').",
    )
    code: str = Field(description="Full TypeScript/TSX source code of the component.")
    props_interface: str = Field(
        default="",
        description="Extracted TypeScript interface for component props.",
    )
    usage_example: str = Field(
        default="",
        description="Code snippet showing how to use this component.",
    )
    design_rationale: str = Field(
        default="",
        description="Brief explanation of design decisions and UX patterns applied.",
    )
    test_code: str = Field(
        default="",
        description="Vitest + Testing Library test for this component.",
    )


class UxComponentResult(BaseModel, frozen=True):
    """Immutable result of UX component generation.

    Contains one or more React components with documentation and
    metadata for auditing and version tracking.
    """

    issue_number: int = Field(description="GitHub Issue number.")
    components: list[GeneratedUxComponent] = Field(
        default_factory=list,
        description="Generated React components.",
    )
    pattern_docs: str = Field(
        default="",
        description="Markdown documentation describing the UX pattern(s) implemented.",
    )
    model_used: str = Field(
        default="",
        description="LLM model identifier used for generation.",
    )
    output_tokens_used: int = Field(
        default=0,
        description="Number of output tokens consumed by the LLM call.",
    )
    prompt_version: str = Field(
        default="v1",
        description="Version tag of the prompt template used.",
    )
    blueprint_hash: str = Field(
        default="",
        description="SHA-256 hash of the blueprint file used as context.",
    )

    @property
    def component_count(self) -> int:
        """Total number of generated components."""
        return len(self.components)

    @property
    def all_paths_valid(self) -> bool:
        """Check that all component paths are in the presentation layer."""
        return all(
            c.file_path.startswith("presentation/components/")
            for c in self.components
        )
